# Nginx config to protect Gunicorn from slow clients
server {
    location / {
        proxy_pass http://127.0.0.1:8000;
        proxy_buffering on;
        proxy_buffer_size 128k;
        proxy_buffers 4 256k;
        proxy_busy_buffers_size 256k;
    }
}

# Nginx Optimized Static File Serving
location /static/ {
    alias /var/www/myproject/static/;
    expires 30d;
    add_header Cache-Control "public, no-transform";
    tcp_nodelay on;
    sendfile on; # Direct kernel-level file transfer
}

# Nginx Upstream with Least Connections
upstream backend_cluster {
    least_conn; # Send to server with fewest active connections
    server 10.0.0.10:8000 max_fails=3 fail_timeout=30s;
    server 10.0.0.11:8000 max_fails=3 fail_timeout=30s;
    server 10.0.0.12:8000 backup; # Only used if others fail
}

